var $bm_rt;
var amp = 40;
var freq = 10;
var decay = 20;
var nK = nearestKey(time);
var n = nK.time <= time ? nK.index : --nK.index;
var t = n === 0 ? 0 : $bm_sub(time, key(n).time);
if (n > 0 && t < 1) {
    var v = velocityAtTime($bm_sub(key(n).time, $bm_div(thisComp.frameDuration, 10)));
    $bm_rt = $bm_sum(value, $bm_div($bm_mul($bm_mul($bm_mul(v, amp), 0.001), Math.sin($bm_mul($bm_mul($bm_mul($bm_mul(freq, 0.1), t), 2), Math.PI))), Math.exp($bm_mul($bm_mul(decay, 0.1), t))));
} else {
    $bm_rt = value;
}

